  const raw = wasQuoted ? value : value.trim();
  if (raw === '') {
    return null;
  }

  const lowered = raw.toLowerCase();
  if (lowered === 'null') {
    return null;
  }

  if (lowered === 'true') {
    return true;
  }

  if (lowered === 'false') {
    return false;
  }

  if (numericRegex.test(raw)) {
    const coerced = Number(raw);
    if (!Number.isNaN(coerced)) {
      return coerced;
    }
  }

  return raw;
