  const quotedFlags: boolean[] = [];
  const delimiterLength = delimiter.length;

  let current = '';
  let fieldQuoted = false;
  let inQuotes = false;

  for (let cursor = 0; cursor < line.length; cursor += 1) {
    const char = line[cursor];

    if (inQuotes) {
      if (char === quote) {
        if (line[cursor + 1] === quote) {
          current += quote;
          cursor += 1;
          continue;
        }

        inQuotes = false;
        continue;
      }

      current += char;
      continue;
    }

