      values.push(current);
      quotedFlags.push(fieldQuoted);
      current = '';
      fieldQuoted = false;
      cursor += delimiterLength - 1;
      continue;
    }

    if (char === quote && current === '') {
      inQuotes = true;
      fieldQuoted = true;
      continue;
    }

