    const grouping = new Map<unknown, Record<string, unknown>[]>();
    for (const row of rows) {
      const key = row[column];
      const bucket = grouping.get(key);
      if (bucket) {
        bucket.push(row);
      } else {
        grouping.set(key, [row]);
      }
    }
    return grouping;
  };

  const filter = (predicate: (row: Record<string, unknown>) => boolean): CSVResult => {
    const filteredRows = rows.filter(predicate);
    return buildResult(filteredRows, headers, errors);
  };

  return {
    rows,
    headers,
    errors,
    filter,
    sum,
    average,
    count,
    groupBy,
  };
