  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? /\r?\n/;

  if (delimiter.length === 0) {
    throw new Error('Delimiter must be a non-empty string');
  }

  if (quote.length === 0) {
    throw new Error('Quote character must be a non-empty string');
  }

  if (typeof lineSeparator === 'string' && lineSeparator.length === 0) {
    throw new Error('Line separator must be non-empty when provided as a string');
  }

  if (input.length === 0) {
    return buildResult([], [], []);
  }

  const rawLines = splitInput(input, lineSeparator);
  let headerLineIndex = -1;

  for (let idx = 0; idx < rawLines.length; idx += 1) {
    if (rawLines[idx].length === 0) {
      continue;
    }
    headerLineIndex = idx;
    break;
  }

  if (headerLineIndex === -1) {
    return buildResult([], [], []);
  }

  const headerLine = rawLines[headerLineIndex];
  const headerParse = parseLine(headerLine, delimiter, quote);

  if (headerParse.error) {
    return buildResult([], [], [
      {
        row: headerLineIndex + 1,
        message: `Header parse error: ${headerParse.error}`,
      },
    ]);
  }

  const headers = headerParse.values.map((headerValue) => headerValue.trim());
  const rows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  for (let idx = headerLineIndex + 1; idx < rawLines.length; idx += 1) {
    const rowLine = rawLines[idx];
    if (rowLine.length === 0) {
      continue;
    }

    const parsed = parseLine(rowLine, delimiter, quote);
    const rowNumber = idx + 1;

    if (parsed.error) {
      errors.push({ row: rowNumber, message: parsed.error });
      continue;
    }

    if (parsed.values.length !== headers.length) {
      errors.push({
        row: rowNumber,
        message: `Row ${rowNumber} has ${parsed.values.length} column(s), expected ${headers.length}`,
      });
    }

    const record: Record<string, unknown> = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex += 1) {
