cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message: string) => {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
};

const assertEqual = (actual: unknown, expected: unknown, message: string) => {
  const serializedActual = JSON.stringify(actual);
  const serializedExpected = JSON.stringify(expected);
  if (serializedActual !== serializedExpected) {
    throw new Error(`${message}\nExpected: ${serializedExpected}\nActual: ${serializedActual}`);
  }
};

function runTests() {
  // Basic parsing
  const simpleInput = 'name,age\nAlice,30\nBob,25';
  const simpleResult = parseCSV(simpleInput);
  assert(simpleResult.errors.length === 0, 'basic parser emitted unexpected errors');
  assert(simpleResult.rows.length === 2, 'basic parser did not produce the expected number of rows');
  assertEqual(simpleResult.headers, ['name', 'age'], 'basic parser headers mismatch');
  assert(simpleResult.rows[0]['name'] === 'Alice', 'first name value mismatch');
  assert(simpleResult.rows[0]['age'] === 30, 'numeric conversion failed for the first row');
  assert(simpleResult.rows[1]['age'] === 25, 'numeric conversion failed for the second row');

  // Quoted fields with commas
  const quotedInput = 'id,name\n1,"Doe, John"\n2,"Smith, Jane"';
  const quotedResult = parseCSV(quotedInput);
  assertEqual(quotedResult.rows[0]['name'], 'Doe, John', 'quoted field with comma not preserved');
  assertEqual(quotedResult.rows[1]['name'], 'Smith, Jane', 'second quoted field not preserved');

  // Escaped quotes
  const escapedInput = 'phrase\n"She said ""hello"" to me"';
  const escapedResult = parseCSV(escapedInput);
  assertEqual(escapedResult.rows[0]['phrase'], 'She said "hello" to me', 'escaped quotes not handled correctly');

  // Custom delimiters and quotes
  const customInput = "id|label\n1|'Comma, inside'\n2|'Another'";
  const customResult = parseCSV(customInput, { delimiter: '|', quote: "'" });
  assertEqual(customResult.rows[0]['label'], 'Comma, inside', 'custom delimiter or quote not respected');

  // Custom line separator
  const customLineSeparatorInput = 'key|value~one|1~two|2';
  const customLineSeparatorResult = parseCSV(customLineSeparatorInput, {
    delimiter: '|',
    lineSeparator: '~',
  });
  assert(customLineSeparatorResult.rows.length === 2, 'custom line separator did not split rows');
  assertEqual(customLineSeparatorResult.rows[1]['value'], 2, 'custom separator parsing failed');

  // Type coercion
  const typeInput = [
    'intCol,floatCol,boolCol,boolColUpper,nullLower,nullUpper,stringCol',
    '10,3.5,true,false,,NULL,hello',
    '0,-1.25,FALSE,TRUE,null,,world',
    ',0.0,False,TRUE,,,"spaced text"',
  ].join('\n');
  const typeResult = parseCSV(typeInput);
  assert(typeResult.rows.length === 3, 'type coercion rows missing');
  assert(typeResult.rows[0]['intCol'] === 10, 'integer detection failed');
  assert(typeResult.rows[0]['floatCol'] === 3.5, 'float detection failed');
  assert(typeResult.rows[0]['boolCol'] === true, 'boolean true detection failed');
  assert(typeResult.rows[0]['boolColUpper'] === false, 'boolean false detection failed');
  assert(typeResult.rows[0]['nullLower'] === null, 'empty field should be null');
  assert(typeResult.rows[0]['nullUpper'] === null, 'NULL literal should be null');
  assert(typeResult.rows[1]['nullLower'] === null, 'lowercase null should be null');
  assert(typeResult.rows[2]['intCol'] === null, 'blank integer column should coerce to null');
  assert(typeResult.rows[2]['stringCol'] === 'spaced text', 'quoted string value lost content');

  // Malformed row collection
  const malformedInput = ['a,b', '1,2,3', '4', '5,"broken'].join('\n');
  const malformedResult = parseCSV(malformedInput);
  assert(malformedResult.rows.length === 2, 'malformed rows still produce data rows');
  assert(malformedResult.errors.length === 3, 'expected three malformed row errors');
  assert(malformedResult.errors[0].row === 2, 'first malformed row has wrong line number');
  assert(malformedResult.errors[0].message.includes('expected'), 'first malformed message is generic');
  assert(malformedResult.errors[2].message.includes('Unterminated'), 'parse error message not collected');

  // Filtering and aggregation
  const aggregateInput = 'name,age,status\nAlice,30,active\nBob,17,active\nCarol,45,inactive\nDave,22,active';
  const aggregateResult = parseCSV(aggregateInput);
  assert(aggregateResult.count() === 4, 'count() should reflect the number of rows');
  assert(aggregateResult.sum('age') === 114, 'sum() of ages incorrect');
  assert(aggregateResult.average('age') === 28.5, 'average() of ages incorrect');
  const grouped = aggregateResult.groupBy('status');
  assert(grouped.get('active')?.length === 3, 'groupBy active bucket incorrect');
  assert(grouped.get('inactive')?.length === 1, 'groupBy inactive bucket incorrect');
  const filtered = aggregateResult.filter((row) => {
    const age = row['age'];
    return typeof age === 'number' && age >= 30;
  });
  assert(filtered.rows.length === 2, 'filtered result should only include older rows');
  assert(filtered.sum('age') === 75, 'filtered sum should only include matching rows');
  assert(filtered.average('age') === 37.5, 'filtered average should only include matching rows');

  // Edge cases
  const emptyResult = parseCSV('');
  assert(emptyResult.rows.length === 0, 'empty input should not produce rows');
  assert(emptyResult.headers.length === 0, 'empty input should not produce headers');
  assert(emptyResult.errors.length === 0, 'empty input should not produce errors');

  const singleColumnResult = parseCSV('only\nvalue');
  assert(singleColumnResult.rows.length === 1, 'single column input should produce one row');
  assert(singleColumnResult.rows[0]['only'] === 'value', 'single column value mismatch');

  const headerOnlyResult = parseCSV('lonely\n');
  assert(headerOnlyResult.rows.length === 0, 'header only should not produce rows');
  assert(headerOnlyResult.headers[0] === 'lonely', 'header only failed to capture header');

  const hugeValue = 'x'.repeat(10000);
  const hugeResult = parseCSV(`payload\n"${hugeValue}"`);
  assert(hugeResult.rows[0]['payload'] === hugeValue, 'large field content mismatch');

  console.log('All csv-parser tests passed');
}

runTests();
