    }

    const record: Record<string, unknown> = {};
    for (let columnIndex = 0; columnIndex < headers.length; columnIndex += 1) {
      const rawValue = columnIndex < parsed.values.length ? parsed.values[columnIndex] : '';
      const wasQuoted = columnIndex < parsed.quoted.length ? parsed.quoted[columnIndex] : false;
      record[headers[columnIndex]] = coerceValue(rawValue, wasQuoted);
    }
    rows.push(record);
  }

  return buildResult(rows, headers, errors);
}
